import threading
import time

class ThreadScheduler:
 def __init__(self, timeQuantum):
 self.timeQuantum = timeQuantum
 self.readyQueue = []
 self.scheduledThreads = []

 def schedule(self, threads):
 for thread in threads:
 self.readyQueue.append(thread)

 while self.readyQueue:
 thread = self.readyQueue.pop(0)
 if thread.timeLeft > self.timeQuantum:
 thread.timeLeft -= self.timeQuantum
 self.readyQueue.append(thread)
 else:
 thread.timeLeft = 0
 self.scheduledThreads.append(thread)

# Example usage:
threads = [Thread(10), Thread(5), Thread(8)]
scheduler = ThreadScheduler(3)
scheduler.schedule(threads)
print(scheduler.scheduledThreads)

#include <stdio.h>
#include <stdlib.h>

typedef struct Thread {
 int timeLeft;
} Thread;

void schedule(Thread* threads, int numThreads, int timeQuantum) {
 Thread* readyQueue = (Thread*)malloc(numThreads * sizeof(Thread));
 int scheduledThreads = 0;

 for (int i = 0; i < numThreads; i++) {
 readyQueue[i] = threads[i];
 }

 while (scheduledThreads < numThreads) {
 Thread thread = readyQueue[0];
 if (thread.timeLeft > timeQuantum) {
 thread.timeLeft -= timeQuantum;
 readyQueue[0] = thread;
 } else {
 thread.timeLeft = 0;
 scheduledThreads++;
 }
 }

 free(readyQueue);
}

// Example usage:
Thread threads[] = {{10}, {5}, {8}};
schedule(threads, 3, 3);
